var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장! 아무나 저 여자 좀 막아 봐!","JPN":"くそっ！　誰かあの女を止めろ！","ENG":"Darn it! Somebody stop her!","TWN":"可惡！給我攔住那個女人！"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"닥치고 도망치기나 해! 형님도 한 방에 처박히는 거 못 봤어?!","JPN":"黙って逃げろ！　兄貴だって一発で吹っ飛ばされたんだぞ！","ENG":"Just shut up and run! Didn't you see that thing take him out in a single blow?","TWN":"閉嘴，快點逃吧！沒看到老大根本就無法招架嗎？！"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"어디로 도망치란 거야! 벽이고 바닥이고 움직이기만 하면 칼이 튀어나오는데!","JPN":"どこに逃げればいいんだよ！　壁も床も、動くだけで剣が飛び出してくるのに！","ENG":"Run? Where to?! We got blades popping out of walls and the floor the moment we move!","TWN":"往哪逃啊！只要一動，牆和地面都會冒出刀刃！"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"이거 다들 군기가 빠졌군.","JPN":"やれやれ、使えない奴ばっかりだな。","ENG":"Looks like we've got a discipline issue among the ranks.","TWN":"簡直就是一盤散沙，還像話嗎。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"내 허락도 없이 도망을 치다니, 요즘 살 만한가 보지?","JPN":"俺の許可なしで逃げるとは、いい度胸だな？","ENG":"I must have grown soft on you, letting you think you can flee without my permission.","TWN":"沒我的允許竟然敢逃走，最近是活的太爽了吧？"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"크, 큰 형님! 오셨습니까!","JPN":"ボ、ボス！","ENG":"B-boss! You're here!","TWN":"大、大哥！您來了！"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"저 여자 때문입니다! 저 여자가 우리 조직을 우습게 보고......!","JPN":"あの女のせいです！　あいつが俺らをバカにしやがって……","ENG":"It's all because of that broad! She thinks she can mess with our gang—","TWN":"都是那個女人！那個女人戲弄我們組織……！"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"컥...... 커헉......","JPN":"ぐあ……ガハッ……","ENG":"Ack... Aack...","TWN":"咳……呃……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"호들갑 좀 떨지 마라. 나도 모르게 주먹이 나갔잖아.","JPN":"大げさだぞ。でかい声出すもんだからつい手が出てしまったじゃないか。","ENG":"Don't get so riled up. You got my fists going before I could think.","TWN":"別在那大驚小怪的，搞的我身體都不自覺的出拳了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"안 그러신가, 아르세니코 패밀리의 후계자 아가씨.","JPN":"この事態をどう思うのかね？　アルセニコファミリーの後継者のお嬢ちゃん。","ENG":"Ain't that right, the heiress of the Arsenicos?","TWN":"是不是啊，阿塞妮克家族的繼承人小姐。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"어째 재수없는 이름이다 싶더니 네놈 사업장이었군.","JPN":"ださい組織名だと思ったら、お前の事業所だったのか。","ENG":"No wonder the name was so lame. So this was your business.","TWN":"我想說這裡名字怎麼如此糟糕，原來是你的窩啊。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"부하들을 위해 덤비겠다면 말리지 않겠어.","JPN":"部下の前でメンツを立てるためにかかってくるなら、応じてやるよ。","ENG":"I won't stop you if you're going to fight for your men.","TWN":"如果你要為你的部下報仇，我沒意見。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하핫. 다른 얼뜨기라면 그랬겠지.","JPN":"ハハッ。他のならず者ならそうするだろうが、俺は違うぞ。","ENG":"Hah hah. I would have, if it was anyone else.","TWN":"哈哈。如果是別人的確可能馬上就衝上去吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하지만 옛 동업자 상대로 굳이 리스크를 감수하고 싶진 않아.","JPN":"かつての同業者を相手に、わざわざリスクを冒す必要はないだろう。","ENG":"But I don't want to take unnecessary risks against a former partner.","TWN":"但對於以前是合夥人的你，我不想承擔風險。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"누가 동업자라는 거냐. 난 이제 패밀리와 아무 관계없어.","JPN":"同業者だと？　私はもうファミリーとは関係ないんだが。","ENG":"Who are you calling a partner? I've got nothing to do with the Family anymore.","TWN":"誰是你合夥人。我現在跟家族已經沒有關係了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런 말은 아버지한테나 가서 하시지.","JPN":"そんなことは親父にでも言え。","ENG":"Why don't you try saying that to my father?","TWN":"這句話你還是留著跟父親說吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......네놈이 아버지를 다시 만날 만큼 뻔뻔하다면 말이지만.","JPN":"……お前が親父に顔を合わせられるほど、図々しい奴ならな。","ENG":"If you're shameless enough to seek his audience ever again, that is.","TWN":"……如果你還有臉去見他的話。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"흐흠, 그러고 보니 그 양반 못 본 지도 꽤 오래됐군.","JPN":"ふむ、そういやしばらく会ってないな。","ENG":"Hmm. Come to think of it, it's been a while since I've seen the good ol' Don.","TWN":"咳嗯，這麼一說，還真的很久沒見到那老頭了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"조만간 꽃이나 한 다발 사서 찾아가야겠어.","JPN":"近いうちに花束でも用意して会いにいかねばな。","ENG":"Perhaps I'll visit soon with some flowers.","TWN":"得找個時間買束花去看看他了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"얘들아, 무기 집어넣고 물러서라.","JPN":"みんな、武器をしまえ。","ENG":"Boys, put down your weapons and fall back.","TWN":"喂，你們收好武器，退下。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"크윽......!","JPN":"くうっ……！","ENG":"Ugh...","TWN":"呃咳……！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"기다려 주십시오, 형님! 저 년은 제 손으로 반드시 처리하겠습니다!","JPN":"お待ちください、ボス！　あのクソ女は俺の手で必ず始末を……！","ENG":"Just give me a moment, boss! I'll take care of that broad myself!","TWN":"等一下，大哥！我一定要親手宰了那個死女人！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"아서라. 급이 맞는 상대한테 덤벼야지.","JPN":"やめとけ。お前が勝てる相手じゃないぞ。","ENG":"Don’t bother. She's way out of your league.","TWN":"算了，你不是她的對手。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"하지만......! 저 여자를 그냥 보내면 다른 조직들이 우릴 얼마나 우습게 보겠습니까!","JPN":"しかし……！　このままあの女を見逃したら、他の組織からバカにされますよ！","ENG":"But... If we just let her walk, what will the other gangs think of us?!","TWN":"可是……！如果就這麼放走那個女人，那豈不是讓其他組織看笑話！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"네 말도 맞아.","JPN":"一理あるな。","ENG":"You've got a point there.","TWN":"你說的也對。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하지만 호라이즌 파이낸스가 상대라면 얘기가 다르지.","JPN":"しかし、相手がホライズン・ファイナンスなら話が違う。","ENG":"But this is Horizon Finance we're dealing with.","TWN":"但如果對手是地平線金融的話，就另當別論了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"호, 호라이즌? 설마 그 피도 눈물도 없다는 사채꾼 말씀이십니까?","JPN":"ホ、ホライズン？　まさかあの血も涙もない闇金業者ですか？","ENG":"H-Horizon? You mean those ruthless, merciless loan sharks?","TWN":"地、地平線？您說的是那個冷血無情的高利貸公司？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그래. 알겠으면 저 꼬마는 이제 풀어 줘.","JPN":"ああ。わかったらそのガキを放してやれ。","ENG":"That’s right. So let the kid go, if you catch my drift.","TWN":"嗯。既然知道了，就放了那個孩子吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 너무 심했어요! 안 다치게 제압할 수 있으면서!","JPN":"リタお姉ちゃん、やりすぎですよ！　怪我させなくても制圧できるのに！","ENG":"You went too far, Rita! You could have neutralized them without hurting them!","TWN":"麗塔姐姐，太過分了！明明可以毫髮無傷的將他們制伏！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"엉겨붙지 마, 꼬맹이. 떨어져 있어.","JPN":"抱きつくな、ガキ。離れろ。","ENG":"Don't get so clingy, kid. Get off me.","TWN":"別黏著我，小鬼。離我遠點。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으앙?! 술 냄새!","JPN":"えっ！？　酒臭い！","ENG":"Huh?! You smell like booze!","TWN":"呃嗯？！酒臭味！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니 또 술 마셨어요? 술 끊겠다고 한 지 사흘도 안 지났는데!","JPN":"また飲んだんですか？　禁酒するって宣言してまだ3日も経ってないのに！","ENG":"Have you been drinking again? It's barely been three days since you promised to quit!","TWN":"姐姐你又喝酒啦？你戒酒還不到三天呢！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그러게 엉겨붙지 말라니까. 이 망할 꼬맹아.","JPN":"だからベタベタすんな、ガキんちょ。","ENG":"Like I said, get off me. You good-for-nothing kid.","TWN":"我叫你別黏著我，你這個小屁孩。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그리고 사흘이면 많이 참은 거지. 사람은 술 담배 없이 살 수 있는 동물이 아냐.","JPN":"3日ってずいぶん我慢した方だぞ。人間は酒とタバコなしで生きていける存在じゃないんだ。","ENG":"Besides, three days were long enough. People aren't meant to live without smoking and drinking.","TWN":"還有，三天已經很長了。人類是沒有煙酒就無法存活的動物。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"끊을 수 있어요, 리타 언니! 제가 응원해 드릴게요!","JPN":"できますよ、リタお姉ちゃん！　私が応援するから！","ENG":"I'm sure you can quit if you just put your mind to it! I'm rooting for you!","TWN":"你可以戒掉的，麗塔姐姐！我為你加油打氣哦！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......뒈지든 말든 모른 척 하고 갈 걸.","JPN":"……叩かれてようがくたばってようが、知らないふりしてどっか行けばよかった。","ENG":"... I should have just let you die.","TWN":"……我真不應該管你死活的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그나저나 호라이즌 파이낸스가 우리 구역엔 무슨 용무지?","JPN":"ところでホライズン・ファイナンスがうちの縄張りに何の用だ？","ENG":"In any case, what brings Horizon Finance to our turf?","TWN":"話說回來，地平線金融來我們的地盤做什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너희 부하들이 끌고 간 빚쟁이한테 선약이 있거든.","JPN":"お前の部下どもに連れ去られた債務者には先約があってね。","ENG":"We have a prior engagement with a debtor your boys snatched up.","TWN":"我要找被你的部下帶走的欠債人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그놈만 넘기면 조용히 돌아가 주지.","JPN":"あいつだけ渡してくれたら大人しく帰ってやるさ。","ENG":"We'll leave quietly if you just hand him over.","TWN":"只要把那個傢伙交給我，我立刻走人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"빌어먹을 년이......! 살아서 걸어 나가는 것도 고마운 줄 모르고!","JPN":"クソアマが……！　生かしてもらっただけ感謝しろ！","ENG":"You cocky punk! You should be grateful we're letting you walk scot-free!","TWN":"可惡的女人……！我們不殺你就該謝天謝地了！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"적당히 해. 내 말이 말 같지 않냐?","JPN":"いい加減にしろ。","ENG":"Easy now. Do you mean to defy me?","TWN":"夠了，你沒聽不懂我剛剛說的話嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"아, 아닙니다!","JPN":"す、すみません！","ENG":"N-no, sir!","TWN":"不、不是的！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"뭐, 그런 거라면 기꺼이 넘겨 주지. 빨대 꽂은 놈이 한둘도 아니고 말이야.","JPN":"まあ、そういうことなら連れていけ。カモれる奴は他にもいる。","ENG":"Well, if that's all you need, you can have him. We've got enough cows to milk as it is.","TWN":"那，既然如此就給你吧。天底下的寄生蟲也不差他一個。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"평의회 정식 회원으로서 전직 회원의 가족 분들에겐 편의를 좀 봐 드려야지.","JPN":"評議会の正式会員として、元会員の家族には助力してあげないとな。","ENG":"As an official member of the Council, it's the least I can do for the daughter of my former colleague.","TWN":"作為評議會的正式會員，理應給前任會員的家屬一點方便。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"정식 회원이라고? 너 같은 놈을?","JPN":"正式会員だと？　お前が？","ENG":"Official member? They accepted the likes of you?","TWN":"正式會員？就憑你？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하하, 그렇게 됐어.","JPN":"ガハハッ、まあな。","ENG":"Hah hah, well, one thing led to another.","TWN":"哈哈，千真萬確。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"네 아버지가 은퇴하는 바람에 새로 자금을 조달할 사람이 필요한가 보더라고.","JPN":"お前の親父が引退したせいで、代わりの資金調達役が必要になったらしくてね。","ENG":"I guess they were strapped for cash with your father's retirement.","TWN":"你父親退休之後，他們似乎需要新的籌資人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 네놈이 배신하고 뒤통수를 친 덕분에 말이지.","JPN":"そうだな。お前が裏切ったおかげでな。","ENG":"Right. Thanks to you, you backstabbing little rat.","TWN":"是啊，這都要歸功於你的背叛。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"아직도 그 소리군. 지나간 일은 흘려보낼 줄도 알아야 할 텐데.","JPN":"まだそんなこと言ってるのか？　過去のことは水に流すことも大事だぞ。","ENG":"That again? Isn't it about time you got over it?","TWN":"都已經是過去的事了，早該拋下過去了吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그래서, 때늦은 복수라도 할 작정인가?","JPN":"で、今更復讐でもするつもりか？","ENG":"So, do you mean to avenge your father after all these years?","TWN":"所以，你是來報仇的？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......말했듯이 난 이제 패밀리와 아무 상관없어. 내 볼일만 마치면 그만이야.","JPN":"……さっきも言ったが、私はもうファミリーと何の関係もない。自分の仕事以外は興味ない。","ENG":"Like I said, the Family's got nothing to do with me anymore. I'm just here to get my job done.","TWN":"……我說過了，我現在跟家族沒有任何關係。辦完我的事就走。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"좋아. 시원시원한 건 여전하군.","JPN":"なるほど。サバサバしているのは相変わらずだな。","ENG":"Very well. I'm glad to see that you're still a straight shooter.","TWN":"好，還是一如既往的爽快。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"어이, 그 녀석 데려 와!","JPN":"おい、あいつを連れてこい！","ENG":"Hey, bring that guy here!","TWN":"哎，把那傢伙帶過來！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"알겠습니다, 형님!","JPN":"承知しました！","ENG":"Yes, sir!","TWN":"是，大哥！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 평의회가 뭐예요?","JPN":"リタお姉ちゃん、評議会ってなんですか？","ENG":"What's this Council you were talking about, Rita?","TWN":"麗塔姐姐，評議會是什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"시궁창 중의 시궁창. 꼬맹이는 몰라도 돼.","JPN":"ドブの中のドブみたいなところさ。子どもは知らなくていい。","ENG":"It's the armpit of all armpits. A little kid like you don't need to know.","TWN":"最醜陋無恥噁心的地方，小孩沒必要知道。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"데려왔습니다, 형님!","JPN":"連れてきました、ボス！","ENG":"Here he is, sir!","TWN":"帶來了，大哥！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"짜식들. 얼굴에 피는 좀 닦아 줄 것이지.","JPN":"あーあ、顔の血くらいは拭いてやれよ。","ENG":"Come on, guys. You could have at least wiped the blood off his face.","TWN":"你們真是，好歹把人家臉上的血跡擦一下。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"자아, 아가씨가 찾던 녀석이야. 겉보기엔 좀 흉해도 숨은 붙어 있으니 안심해.","JPN":"さあ、お嬢ちゃんが探していた奴だ。ああ見えても息はしているから安心しろ。","ENG":"Here's the man you were looking for. Don’t worry about him looking a bit rough. He's still breathing.","TWN":"這就是你要找的那個人。雖然看起來有點慘，但還有呼吸，放心吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"거래에는 여전히 확실하군.","JPN":"相変わらず取引はしっかりしてるな。","ENG":"So you held up your end of the bargain, as usual.","TWN":"對於交易還是這麼一絲不苟。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"오랜만에 만나서 더러웠다. 다시 만날 일 없길 바라지.","JPN":"久しぶり会えて不快だった。どうかもう二度と会わないことを願うよ。","ENG":"Well, I can't say it's been a pleasure. I hope I never have to see you again.","TWN":"重新遇見你還是讓人很不舒服，希望後會無期。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하핫. 아쉽군. 난 꽤나 반가웠는데 말이야.","JPN":"ハハハ、残念だな。俺は会えて嬉しかったぞ。","ENG":"Hah hah. That's too bad. I was rather glad to see you.","TWN":"哈哈，真遺憾。我倒是很高興再次見到你呢。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"......그럼 살펴 가라고. 아가씨.","JPN":"……それじゃあ気を付けて帰りな、お嬢ちゃん。","ENG":"Take care, then. My lady.","TWN":"……那您慢走，大小姐。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};